import{_ as a}from"./chunks/填写注册信息.s1f7Rwd8.js";import{_ as i}from"./chunks/修改密码.D8STuWDZ.js";import{_ as t,o as e,c as r,ae as o}from"./chunks/framework.CB71nIlf.js";const n="/cogniand-manual.github.io/assets/%E9%80%80%E5%87%BA%E7%99%BB%E5%BD%95.D-AkTL01.png",f=JSON.parse('{"title":"主试注册与登录","description":"","frontmatter":{},"headers":[],"relativePath":"2-experimenter-manual/2-registration-login.md","filePath":"2-experimenter-manual/2-registration-login.md"}'),h={name:"2-experimenter-manual/2-registration-login.md"};function s(u,l,d,c,p,m){return e(),r("div",null,[...l[0]||(l[0]=[o('<h1 id="主试注册与登录" tabindex="-1">主试注册与登录 <a class="header-anchor" href="#主试注册与登录" aria-label="Permalink to &quot;主试注册与登录&quot;">​</a></h1><p>本页面详细介绍主试如何注册账户、登录平台以及相关的账户管理功能。</p><h2 id="注册账户" tabindex="-1">注册账户 <a class="header-anchor" href="#注册账户" aria-label="Permalink to &quot;注册账户&quot;">​</a></h2><h3 id="访问注册页面" tabindex="-1">访问注册页面 <a class="header-anchor" href="#访问注册页面" aria-label="Permalink to &quot;访问注册页面&quot;">​</a></h3><ol><li>打开 CogniAND 平台首页</li><li>点击页面右上角的&quot;注册&quot;按钮</li><li>进入注册页面</li></ol><h3 id="填写注册信息" tabindex="-1">填写注册信息 <a class="header-anchor" href="#填写注册信息" aria-label="Permalink to &quot;填写注册信息&quot;">​</a></h3><p>注册表单包含以下必填项：</p><h4 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h4><ul><li><p><strong>用户名</strong></p><ul><li>用于登录和在平台上显示</li><li>3-20 个字符</li><li>支持中文、英文、数字和下划线</li><li>用户名一旦注册不可修改</li></ul></li><li><p><strong>邮箱地址</strong></p><ul><li>用于接收验证邮件和重要通知</li><li>必须是有效的邮箱地址</li><li>一个邮箱只能注册一个账户</li><li>建议使用常用邮箱，确保能及时收到通知</li></ul></li><li><p><strong>密码</strong></p><ul><li>至少 8 个字符</li><li>建议包含大小写字母、数字和特殊字符</li><li>不要使用过于简单的密码（如 123456）</li><li>不要使用与用户名相同的密码</li></ul></li><li><p><strong>确认密码</strong></p><ul><li>再次输入密码以确认</li><li>必须与上面输入的密码完全一致</li></ul><p><img src="'+a+'" alt="注册页面"></p></li></ul><h2 id="登录平台" tabindex="-1">登录平台 <a class="header-anchor" href="#登录平台" aria-label="Permalink to &quot;登录平台&quot;">​</a></h2><h3 id="登录方式" tabindex="-1">登录方式 <a class="header-anchor" href="#登录方式" aria-label="Permalink to &quot;登录方式&quot;">​</a></h3><p>CogniAND 平台支持以下登录方式：</p><h4 id="用户名-邮箱-密码登录" tabindex="-1">用户名/邮箱 + 密码登录 <a class="header-anchor" href="#用户名-邮箱-密码登录" aria-label="Permalink to &quot;用户名/邮箱 + 密码登录&quot;">​</a></h4><ol><li>访问平台首页</li><li>点击&quot;登录&quot;按钮</li><li>输入用户名或邮箱</li><li>输入密码</li><li>点击&quot;登录&quot;</li></ol><p><strong>可选功能：</strong></p><ul><li><strong>记住我</strong>：勾选后，下次访问时自动填充用户名</li><li><strong>自动登录</strong>：勾选后，7 天内无需重复登录（不建议在公共电脑上使用）</li></ul><h2 id="密码管理" tabindex="-1">密码管理 <a class="header-anchor" href="#密码管理" aria-label="Permalink to &quot;密码管理&quot;">​</a></h2><h3 id="修改密码" tabindex="-1">修改密码 <a class="header-anchor" href="#修改密码" aria-label="Permalink to &quot;修改密码&quot;">​</a></h3><p><img src="'+i+'" alt="注册页面"></p><p><strong>密码要求：</strong></p><ul><li>至少 8 个字符</li><li>建议包含大小写字母、数字和特殊字符</li><li>不能与最近 3 次使用的密码相同</li><li>不能与用户名相同</li></ul><h2 id="账户安全" tabindex="-1">账户安全 <a class="header-anchor" href="#账户安全" aria-label="Permalink to &quot;账户安全&quot;">​</a></h2><h3 id="安全建议" tabindex="-1">安全建议 <a class="header-anchor" href="#安全建议" aria-label="Permalink to &quot;安全建议&quot;">​</a></h3><p>为了保护您的账户安全，建议：</p><ol><li><p><strong>使用强密码</strong></p><ul><li>包含大小写字母、数字和特殊字符</li><li>不要使用生日、电话号码等容易被猜到的信息</li><li>定期更换密码（建议 3-6 个月更换一次）</li></ul></li><li><p><strong>保护登录信息</strong></p><ul><li>不要与他人共享账户</li><li>不要在公共电脑上保存密码</li><li>使用后及时退出登录</li></ul></li><li><p><strong>警惕钓鱼邮件</strong></p><ul><li>平台不会通过邮件索要密码</li><li>注意识别伪造的登录页面</li><li>只在官方网站登录</li></ul></li><li><p><strong>定期检查登录记录</strong></p><ul><li>在&quot;账户安全&quot;中查看最近的登录记录</li><li>如发现异常登录，立即修改密码</li></ul></li></ol><h2 id="退出登录" tabindex="-1">退出登录 <a class="header-anchor" href="#退出登录" aria-label="Permalink to &quot;退出登录&quot;">​</a></h2><h3 id="如何退出" tabindex="-1">如何退出 <a class="header-anchor" href="#如何退出" aria-label="Permalink to &quot;如何退出&quot;">​</a></h3><ol><li>点击右上角头像</li><li>在下拉菜单中选择&quot;退出登录&quot;</li><li>确认退出 <img src="'+n+'" alt="注册页面"></li></ol><div class="tip custom-block"><p class="custom-block-title">提示</p><p>如果勾选了&quot;自动登录&quot;，退出后仍会保留登录状态。如需完全退出，请在退出前取消勾选&quot;自动登录&quot;。</p></div><h2 id="多设备登录" tabindex="-1">多设备登录 <a class="header-anchor" href="#多设备登录" aria-label="Permalink to &quot;多设备登录&quot;">​</a></h2><h3 id="支持情况" tabindex="-1">支持情况 <a class="header-anchor" href="#支持情况" aria-label="Permalink to &quot;支持情况&quot;">​</a></h3><ul><li>平台支持在多个设备上同时登录</li><li>同一账户可以在电脑、平板、手机上使用</li><li>数据会在所有设备间同步</li></ul><h3 id="安全提示" tabindex="-1">安全提示 <a class="header-anchor" href="#安全提示" aria-label="Permalink to &quot;安全提示&quot;">​</a></h3><ul><li>定期检查登录设备列表</li><li>如发现未知设备，立即修改密码</li><li>不建议在不信任的设备上登录</li></ul><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><p>完成注册和登录后，您可以：</p><ul><li>📖 返回<a href="./1-getting-started.html">快速开始</a>了解主试功能概览</li><li>🔬 学习如何<a href="./3-experiment-management/3-2-create-experiment.html">创建实验</a></li><li>📚 探索<a href="./4-template-library.html">模板库</a>快速开始</li><li>👤 完善<a href="./7-backstage.html">个人资料</a>提升专业形象</li></ul><hr><p><strong>遇到问题？</strong> 查看<a href="/cogniand-manual.github.io/1-FAQ/1-account.html">常见问题</a>或联系<a href="/cogniand-manual.github.io/7-technical-support/1-contact.html">技术支持</a>。</p>',39)])])}const _=t(h,[["render",s]]);export{f as __pageData,_ as default};
